'use strict';

/**
* Compute the correlation distance between two double-precision floating-point strided arrays.
*
* @module @stdlib/stats-strided-distances-dcorrelation
*
* @example
* var Float64Array = require( '@stdlib/array-float64' );
* var dcorrelation = require( '@stdlib/stats-strided-distances-dcorrelation' );
*
* var x = new Float64Array( [ 1.0, -2.0, 2.0 ] );
* var y = new Float64Array( [ 2.0, -2.0, 1.0 ] );
*
* var v = dcorrelation( x.length, x, 1, y, 1 );
* // returns ~0.115
*
* @example
* var Float64Array = require( '@stdlib/array-float64' );
* var dcorrelation = require( '@stdlib/stats-strided-distances-dcorrelation' );
*
* var x = new Float64Array( [ 1.0, -2.0, 2.0 ] );
* var y = new Float64Array( [ 2.0, -2.0, 1.0 ] );
*
* var v = dcorrelation.ndarray( x.length, x, 1, 0, y, 1, 0 );
* // returns ~0.115
*/

// MODULES //

var join = require( 'path' ).join;
var tryRequire = require( '@stdlib/utils-try-require' );
var isError = require( '@stdlib/assert-is-error' );
var main = require( './main.js' );


// MAIN //

var dcorrelation;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	dcorrelation = main;
} else {
	dcorrelation = tmp;
}


// EXPORTS //

module.exports = dcorrelation;

// exports: { "ndarray": "dcorrelation.ndarray" }
